module multi_pipe_8bit(
    input clk, input rst_n, input mul_en_in, input [7:0] mul_a, input [7:0] mul_b,
    output mul_en_out, output [15:0] mul_out
); 
    reg [7:0] mul_a_reg, mul_b_reg;
    reg [15:0] mul_out_reg;
    reg [15:0] temp [7:0];
    reg [15:0] sum [7:0];
    reg mul_en_out_reg;

    integer i, j, k;
    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_en_out_reg <= 1'b0;
        end
        else begin
            mul_en_out_reg <= mul_en_in;
        end
    end

    assign mul_en_out = mul_en_out_reg;

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_a_reg <= 8'b0;
            mul_b_reg <= 8'b0;
        end
        else begin
            if(mul_en_in) begin
                mul_a_reg <= mul_a;
                mul_b_reg <= mul_b;
            end
        end
    end

    always@(*) begin
        for(i=0; i<8; i=i+1) begin
            case(mul_b_reg[i])
                1'b0: temp[i] = 16'b0;
                1'b1: temp[i] = {8'b0, mul_a_reg};
        endcase
    end

    end // Auto-repaired
    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            for(j=0; j<8; j=j+1) begin
                sum[j] <= 16'b0;
            end
        end
        else begin
            for(k=0; k<8; k=k+1) begin
                if(k==0) begin
                    sum[k] <= temp[k];
                end
                else begin
                    sum[k] <= {sum[k-1][15:8] + temp[k][15:8], sum[k-1][7:0] + temp[k][7:0]};
                end
            end
        end
    end

    always@(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_out_reg <= 16'b0;
        end
        else begin
            mul_out_reg <= sum[7];
        end
    end

    assign mul_out = (mul_en_out_reg) ? mul_out_reg : 16'b0;
endmodule
